+function decodeAsciiBytes(bytes: Uint8Array): string {
+  if (textDecoder) return textDecoder.decode(bytes);
+
+  const CHUNK = 0x2000;
+  let out = '';
+  for (let i = 0; i < bytes.length; i += CHUNK) {
+    const chunk = bytes.subarray(i, i + CHUNK);
+    out += String.fromCharCode(...chunk);
+  }
+  return out;
+}
